const idMap = {
  '6a0b76ac0f308f03cb0ae8fd': '685d40e60c7815d8080d5084', // Nome e sobrenome
  '6a0b76ac0f308f03cb0ae8fe': '685d40f2f8f9e3904c0b0eb4', // WhatsApp
  '6a0b76ac0f308f03cb0ae8ff': '685d40fd0c7815d8080d5085', // Instagram
  '6a0b76ac0f308f03cb0ae903': '685d43c035bd886b580246b4', // E-mail
  '6a0b76ac0f308f03cb0ae8f9': '685d40a0b13a7bb2320f94dd', // Faturamento mensal
  '6a0b76ac0f308f03cb0ae8f6': '685d402c58ad4238f4082362', // Qual opção te representa
  '6a0b76ac0f308f03cb0ae8f7': '685d404b97e30a0017089364', // Ticket da mentoria
  '6a0b76ac0f308f03cb0ae8f8': '685d407a97e30a0017089369', // Curso/infoproduto
  '6a0b76ac0f308f03cb0ae8fa': '685d40b0b13a7bb2320f94df', // Nicho
  '6a0b76ac0f308f03cb0ae8fb': '685d40cb0c7815d8080d5082', // Objetivo de faturamento 12m
  '6a0b76ac0f308f03cb0ae8fc': '685d40d66128d7c13205cfa8', // Principal dificuldade
  '6a0b76ac0f308f03cb0ae905': '68712c954b2c93e188055a47', // Por que a Consultoria é ideal
  '6a0b76ac0f308f03cb0ae906': '68712c9e11c21c36a3063c64', // Por que aceitar aplicação
};

const results = [];

for (const item of $input.all()) {
  const data = item.json;
  const answers = data?.body?.response?.answers;

  if (!answers || typeof answers !== 'object') {
    results.push(item);
    continue;
  }

  const remappedAnswers = {};
  for (const [oldId, value] of Object.entries(answers)) {
    const newId = idMap[oldId] || oldId; // se não existir mapeamento, mantém o ID original
    remappedAnswers[newId] = value;
  }

  results.push({
    json: {
      ...data,
      body: {
        ...data.body,
        response: {
          ...data.body.response,
          answers: remappedAnswers,
        },
      },
    },
  });
}

return results;

